constexpr int kBlockSize = 256;
using benchmark_scalar_t = double;

template <typename T>
__device__ inline T gpu_atomic_add(T* address, T val);

template <>
__device__ inline float gpu_atomic_add<float>(float* address, float val) {
  return atomicAdd(address, val);
}

template <>
__device__ inline int gpu_atomic_add<int>(int* address, int val) {
  return atomicAdd(address, val);
}

template <>
__device__ inline double gpu_atomic_add<double>(double* address, double val) {
#if __CUDA_ARCH__ >= 600
  return atomicAdd(address, val);
#else
  unsigned long long int* address_as_ull =
      reinterpret_cast<unsigned long long int*>(address);
  unsigned long long int old = *address_as_ull, assumed;
  do {
    assumed = old;
    old = atomicCAS(address_as_ull, assumed,
                    __double_as_longlong(val +
                                         __longlong_as_double(assumed)));
  } while (assumed != old);
  return __longlong_as_double(old);
#endif
}

template <typename Element, unsigned int compute_iterations>
__device__ __forceinline__ Element bench_value(const Element* data, size_t i) {
#ifdef BASELINE_IMPL
  Element t = data[i];
  const Element f = data[0];
#pragma unroll
  for (unsigned int j = 0; j < compute_iterations; ++j) {
    t = t * t + f;
  }
  return t;
#else
  const Element f0 = data[0];
  const Element f1 = data[1];
  const Element f2 = data[2];
  const Element f3 = data[3];
  const Element f4 = data[4];
  const Element f5 = data[5];
  const Element f6 = data[6];
  const Element f7 = data[7];

  const Element v = data[i];
  Element t0 = v;
  Element t1 = v;
  Element t2 = v;
  Element t3 = v;
  Element t4 = v;
  Element t5 = v;
  Element t6 = v;
  Element t7 = v;

#pragma unroll
  for (unsigned int j = 0; j < compute_iterations / 8; ++j) {
    t0 = t0 * t0 + f0;
    t1 = t1 * t1 + f1;
    t2 = t2 * t2 + f2;
    t3 = t3 * t3 + f3;
    t4 = t4 * t4 + f4;
    t5 = t5 * t5 + f5;
    t6 = t6 * t6 + f6;
    t7 = t7 * t7 + f7;
  }
  if constexpr (compute_iterations % 8 > 0) {
    t0 = t0 * t0 + f0;
  }
  if constexpr (compute_iterations % 8 > 1) {
    t1 = t1 * t1 + f1;
  }
  if constexpr (compute_iterations % 8 > 2) {
    t2 = t2 * t2 + f2;
  }
  if constexpr (compute_iterations % 8 > 3) {
    t3 = t3 * t3 + f3;
  }
  if constexpr (compute_iterations % 8 > 4) {
    t4 = t4 * t4 + f4;
  }
  if constexpr (compute_iterations % 8 > 5) {
    t5 = t5 * t5 + f5;
  }
  if constexpr (compute_iterations % 8 > 6) {
    t6 = t6 * t6 + f6;
  }
  return t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
#endif
}

template <typename Element, unsigned int compute_iterations>
__global__ void bench_kernel(Element* data, size_t len, Element* out_sum) {
  __shared__ Element shared[kBlockSize];

  const unsigned int tid = threadIdx.x;
  const size_t global_tid =
      static_cast<size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
  const size_t stride =
      static_cast<size_t>(blockDim.x) * static_cast<size_t>(gridDim.x);

  Element local_sum = static_cast<Element>(0);

  for (size_t i = global_tid; i < len; i += stride) {
    local_sum += bench_value<Element, compute_iterations>(data, i);
  }

  shared[tid] = local_sum;
  __syncthreads();

  for (unsigned int offset = blockDim.x / 2; offset > 0; offset >>= 1) {
    if (tid < offset) {
      shared[tid] += shared[tid + offset];
    }
    __syncthreads();
  }

  if (tid == 0) {
    gpu_atomic_add(out_sum, shared[0]);
  }
}

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len,
             const Element /*seed1*/,
             const Element /*seed2*/,
             Element* d_src,
             Element* d_sum,
             int grid_size) {
  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(Element)));
  bench_kernel<Element, compute_iterations>
      <<<grid_size, kBlockSize>>>(d_src, len, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());
  CUDA_SAFE_CALL(
      cudaMemcpy(d_src, d_sum, sizeof(Element), cudaMemcpyDeviceToDevice));
  return len;
}

template <typename Op>
benchmark_scalar_t measure_operation(Op op) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));
  CUDA_SAFE_CALL(cudaEventRecord(start));
  op();
  CUDA_SAFE_CALL(cudaEventRecord(stop));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));
  float elapsed_ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&elapsed_ms, start, stop));
  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));
  return static_cast<benchmark_scalar_t>(elapsed_ms);
}

template <typename Op>
benchmark_scalar_t benchmark_cuda(Op op) {
  constexpr int total_runs = 20;

  auto duration = op();
  std::vector<benchmark_scalar_t> measurements;
  measurements.reserve(total_runs - 1);

  for (int i = 1; i < total_runs; ++i) {
    duration = op();
    measurements.push_back(duration);
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <typename T>
int grid_size_for_len(size_t len) {
  cudaDeviceProp prop{};
  int device = 0;
  CUDA_SAFE_CALL(cudaGetDevice(&device));
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&prop, device));
  size_t needed = (len + kBlockSize - 1) / kBlockSize;
  size_t preferred = static_cast<size_t>(prop.multiProcessorCount) * 32;
  if (preferred == 0) preferred = 1;
  size_t grid = std::min(needed == 0 ? size_t{1} : needed, preferred);
  return static_cast<int>(grid == 0 ? 1 : grid);
}

long long runbench_warmup(void* d_buffer, size_t size_bytes, void* d_sum) {
  const size_t num_elements = size_bytes / sizeof(double);
  const int grid_size = grid_size_for_len<double>(num_elements);
  auto duration_ms = measure_operation([&] {
    bench<double, 16>(num_elements, 1.0, -1.0,
                      reinterpret_cast<double*>(d_buffer),
                      reinterpret_cast<double*>(d_sum), grid_size);
  });
  return static_cast<long long>(duration_ms * 1000.0);
}

template <unsigned int compute_iterations>
void runbench(void* d_buffer, size_t size_bytes, void* d_sum) {
  ComputeSpace cs{size_bytes, static_cast<int>(compute_iterations)};

  float* c_as_float = reinterpret_cast<float*>(d_buffer);
  const int grid_float = grid_size_for_len<float>(cs.element_count<float>());
  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f,
                                       c_as_float,
                                       reinterpret_cast<float*>(d_sum),
                                       grid_float);
    });
  });

  double* c_as_double = reinterpret_cast<double*>(d_buffer);
  const int grid_double = grid_size_for_len<double>(cs.element_count<double>());
  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench<double, compute_iterations>(cs.element_count<double>(), 1.0, -1.0,
                                        c_as_double,
                                        reinterpret_cast<double*>(d_sum),
                                        grid_double);
    });
  });

  int* c_as_int = reinterpret_cast<int*>(d_buffer);
  const int grid_int = grid_size_for_len<int>(cs.element_count<int>());
  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int,
                                     reinterpret_cast<int*>(d_sum), grid_int);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)
            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* d_buffer, size_t size_bytes, void* d_sum) {
  runbench<compute_iterations>(d_buffer, size_bytes, d_sum);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* d_buffer, size_t size_bytes, void* d_sum) {
  runbench_range<j1>(d_buffer, size_bytes, d_sum);
  runbench_range<j2, Args...>(d_buffer, size_bytes, d_sum);
}

